// Merge all paginated pages into one record list, then compute funnel metrics.
const pages = $input.all();
let recs = [];
for (const p of pages) { recs = recs.concat((p.json.records || [])); }
const f = recs.map(r => r.fields || {});
const n = f.length;
const count = (pred) => f.filter(pred).length;
const byStatus = {};
for (const x of f) { const s = x.Status || 'Unknown'; byStatus[s] = (byStatus[s]||0)+1; }
const byClass = { Hot: count(x=>x.Classification==='Hot'), Warm: count(x=>x.Classification==='Warm'), Cold: count(x=>x.Classification==='Cold') };
const contacted = count(x=>['Contacted','Replied','Negotiating','Won','Lost'].includes(x.Status));
const replied = count(x=>['Replied','Negotiating','Won'].includes(x.Status));
const won = byStatus['Won']||0;
const negotiating = byStatus['Negotiating']||0;
const pct = (a,b)=> b? Math.round((a/b)*1000)/10 : 0;
// per-industry response rate
const ind = {};
for (const x of f) { const i = x.Industry || 'Unknown'; ind[i] = ind[i] || { contacted:0, replied:0 }; if(['Contacted','Replied','Negotiating','Won','Lost'].includes(x.Status)) ind[i].contacted++; if(['Replied','Negotiating','Won'].includes(x.Status)) ind[i].replied++; }
const industryRates = Object.entries(ind).filter(([,v])=>v.contacted>=2).map(([k,v])=>({ industry:k, contacted:v.contacted, replied:v.replied, rate:pct(v.replied,v.contacted) })).sort((a,b)=>b.rate-a.rate);
const avgScore = n? Math.round(f.reduce((s,x)=>s+(Number(x['Lead Score'])||0),0)/n) : 0;
const metrics = { total: n, byStatus, byClass, contacted, replied, negotiating, won, responseRate: pct(replied, contacted), winRate: pct(won, contacted), avgScore, industryRates };
return [{ json: { metrics } }];
